    func fetchUserData(completion: @escaping (Result<UserData, Error>) -> Void) {
        let url = Environment.production.baseURL.appendingPathComponent("user")
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.addValue("Bearer \(getAccessToken())", forHTTPHeaderField: "Authorization")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
